#include <stdio.h>
#include <stdlib.h>

int a[1000000];
int size = 0;

void foo(long long n, int r) {
    a[size++] = n;
    if (n > 10LL * r) {
        return;
    }
    foo(10LL * n + 4, r);
    foo(10LL * n + 7, r);
}

int compare(const void *x, const void *y) {
    long long xx = *(long long*)x;
    long long yy = *(long long*)y;
    if (xx > yy) return 1;
    if (xx < yy) return -1;
    return 0;
}

long long get_sum(long long m) {
    long long s = 0;
    for (int i = 1; i < size; i++) {
        long long min1 = a[i] < m ? a[i] : m;
        long long min2 = a[i-1] < m ? a[i-1] : m;
        s += a[i] * (min1 - min2);
    }
    return s;
}

int main() {
    int l, r;
    scanf("%d %d", &l, &r);
    foo(0, r);
    qsort(a, size, sizeof(long long), compare);
    printf("%lld\n", get_sum(r) - get_sum(l - 1));
    return 0;
}
