#include <stdio.h>
#include <stdlib.h>

int *a;
int size = 0;
int capacity = 0;

void foo(long long n, int r) {
    if (size >= capacity) {
        capacity = capacity == 0 ? 1 : capacity * 2;
        a = realloc(a, capacity * sizeof(int));
    }
    a[size++] = n;
    if (n > 10 * r) {
        return;
    }
    foo(10 * n + 4, r);
    foo(10 * n + 7, r);
}

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

long long get_sum(long long m) {
    long long s = 0;
    for (int i = 1; i < size; i++) {
        s += a[i] * ( (a[i] < m ? a[i] : m) - (a[i-1] < m ? a[i-1] : m) );
    }
    return s;
}

int main() {
    int l, r;
    scanf("%d %d", &l, &r);

    a = NULL;
    size = 0;
    capacity = 0;
    foo(0, r);
    qsort(a, size, sizeof(int), compare);

    printf("%lld\n", get_sum(r) - get_sum(l - 1));

    free(a);
    return 0;
}
